import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

const Login = ({ onLoginSuccess }) => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);
        try {
            const res = await api.post('/auth/login', formData);
            if (res.data?.token) {
                localStorage.setItem('token', res.data.token);
                localStorage.setItem('user_name', res.data.user?.nama_lengkap || 'User');
                alert('Login Berhasil!');
                if (onLoginSuccess) onLoginSuccess();
                navigate('/');
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Email atau password salah!');
        } finally {
            setLoading(false);
        }
    };

    const styles = {
        container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', backgroundColor: '#fffbf7', padding: '20px' },
        card: { width: '100%', maxWidth: '400px', background: 'linear-gradient(180deg, #1c0d02 0%, #2e1505 100%)', borderRadius: '24px', padding: '40px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.3)', color: '#fef3c7' },
        brand: { textAlign: 'center', marginBottom: '32px' },
        logo: { fontSize: '24px', fontWeight: '900', background: 'linear-gradient(135deg, #fb923c 0%, #facc15 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', margin: 0 },
        subBrand: { fontSize: '10px', color: '#ea580c', letterSpacing: '4px', fontWeight: '800', textTransform: 'uppercase', marginTop: '8px' },
        label: { fontSize: '12px', fontWeight: '700', color: '#fb923c', textTransform: 'uppercase', display: 'block', marginBottom: '8px' },
        input: { width: '100%', padding: '14px', borderRadius: '12px', border: '1px solid #4a2c17', backgroundColor: '#2e1d11', fontSize: '14px', color: '#fef3c7', marginBottom: '20px', boxSizing: 'border-box' },
        btn: { width: '100%', padding: '14px', borderRadius: '12px', border: 'none', background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)', color: '#fff', fontWeight: '700', cursor: 'pointer', fontSize: '15px' },
        btnGuest: { width: '100%', padding: '14px', borderRadius: '12px', border: '1px solid #ea580c', background: 'transparent', color: '#fb923c', fontWeight: '700', cursor: 'pointer', marginTop: '12px', fontSize: '14px' },
        error: { padding: '12px', background: '#450a0a', color: '#fca5a5', borderRadius: '8px', fontSize: '12px', marginBottom: '20px', textAlign: 'center' }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <div style={styles.brand}>
                    <h1 style={styles.logo}>YerusSolo</h1>
                    <div style={styles.subBrand}>Job Portal</div>
                </div>
                {error && <div style={styles.error}>{error}</div>}
                <form onSubmit={handleLogin}>
                    <label style={styles.label}>Email</label>
                    <input type="email" name="email" value={formData.email} onChange={handleChange} style={styles.input} required />
                    <label style={styles.label}>Password</label>
                    <input type="password" name="password" value={formData.password} onChange={handleChange} style={styles.input} required />
                    <button type="submit" style={styles.btn}>{loading ? 'Memverifikasi...' : 'Masuk Akun'}</button>
                </form>
                <button type="button" onClick={() => navigate('/')} style={styles.btnGuest}>🔍 Jelajahi Sebagai Guest</button>
            </div>
        </div>
    );
};

export default Login;
